/**
 * @summary Get all orders (admin)
 */
export const getAdminGetOrdersUrl = (params?: AdminGetOrdersParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/orders?${stringifiedParams}`
    : `/api/admin/orders`;
};

export const adminGetOrders = async (
  params?: AdminGetOrdersParams,
  options?: RequestInit,
): Promise<OrderWithUser[]> => {
  return customFetch<OrderWithUser[]>(getAdminGetOrdersUrl(params), {
    ...options,
    method: "GET",
  });
};

